-- Applies only wcvp_id/powo_id and will not overwrite a different existing prod wcvp_id.
-- Based off running the WCVP match against all hosts. Run locally as it is much faster.

BEGIN;

ON CONFLICT (species_id) DO UPDATE
SET wcvp_id = EXCLUDED.wcvp_id,
    powo_id = EXCLUDED.powo_id
WHERE host_traits.wcvp_id IS NULL
   OR host_traits.wcvp_id = ''
   OR host_traits.wcvp_id = EXCLUDED.wcvp_id;

COMMIT;
